import{c as e,Q as r,j as a,m as d}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"AgentOpt v0.1: Client-Side Optimization for LLM-Based Agents","description":"","frontmatter":{"url":"https://arxiv.org/abs/2604.06296","title":"AgentOpt v0.1: Client-Side Optimization for LLM-Based Agents","date":"2026-04-07T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-07-agentopt-client-side-optimization.md","filePath":"research/ai-articles/scored/2026-04-07-agentopt-client-side-optimization.md","lastUpdated":1779796674000}'),o={name:"research/ai-articles/scored/2026-04-07-agentopt-client-side-optimization.md"};function n(i,t,s,l,h,p){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="agentopt-v0-1-client-side-optimization-for-llm-based-agents" tabindex="-1">AgentOpt v0.1: Client-Side Optimization for LLM-Based Agents <a class="header-anchor" href="#agentopt-v0-1-client-side-optimization-for-llm-based-agents" aria-label="Permalink to &quot;AgentOpt v0.1: Client-Side Optimization for LLM-Based Agents&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/abs/2604.06296" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.06296</a><br><strong>作者</strong>：Wenyue Hua 等 7 位<br><strong>發表日期</strong>：2026-04-07（v1），2026-04-15（v2）<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h3><p>在多步驟 Agent pipeline 中，<strong>模型組合的選擇比個別模型能力更重要</strong>。強模型不一定是每個角色的最佳選擇；錯誤的組合可能同時浪費成本又損害品質。</p><p><strong>框架定位</strong>：Client-side 優化 — 在不修改 Agent 程式碼的情況下，透過攔截 httpx 傳輸層（patching <code>httpx.Client.send()</code>），系統性地找到最佳模型組合。</p><h3 id="標題結論-最強模型當-planner-反而最差" tabindex="-1">標題結論：最強模型當 Planner 反而最差 <a class="header-anchor" href="#標題結論-最強模型當-planner-反而最差" aria-label="Permalink to &quot;標題結論：最強模型當 Planner 反而最差&quot;">​</a></h3><p>在 HotpotQA（多跳問答）測試：</p><table tabindex="0"><thead><tr><th>組合</th><th>準確率</th></tr></thead><tbody><tr><td>Claude Opus 4.6（規劃者 + 求解者）</td><td><strong>31.71%</strong></td></tr><tr><td>Ministral 3 8B（規劃者）+ Claude Opus 4.6（求解者）</td><td><strong>74.27%</strong></td></tr></tbody></table><p><strong>原因</strong>：Claude Opus 4.6 作為規劃者時，傾向「自己全部做完」，<strong>繞過下游求解者</strong>——讓強模型餓死了 pipeline。</p><p><strong>推論</strong>：</p><ul><li>強 ≠ 在每個角色最佳</li><li>懂得委派的弱規劃者 &gt; 什麼都做的強規劃者</li><li>與 cc-workspace 的「parent 協調 + sub-agent 執行」架構一致</li></ul><h3 id="成本差距量化" tabindex="-1">成本差距量化 <a class="header-anchor" href="#成本差距量化" aria-label="Permalink to &quot;成本差距量化&quot;">​</a></h3><blockquote><p>「在相同準確率下，最佳與最差模型組合的成本差距達 <strong>13× 到 32×</strong>。」</p></blockquote><p>這代表：在相同品質下，選擇正確的模型組合可以節省 93-97% 的成本。</p><h3 id="搜索算法-10-種-v2" tabindex="-1">搜索算法（10 種，v2） <a class="header-anchor" href="#搜索算法-10-種-v2" aria-label="Permalink to &quot;搜索算法（10 種，v2）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>算法</th><th>類型</th></tr></thead><tbody><tr><td><strong>UCB-E（v2 最佳）</strong></td><td>Bandit（+ Low-Rank Factorization 變體）</td></tr><tr><td><strong>Arm Elimination（v1 最佳）</strong></td><td>Bandit（逐步淘汰 UCB 低於領先者的組合）</td></tr><tr><td>Epsilon-LUCB</td><td>Bandit</td></tr><tr><td>Threshold Successive Elimination</td><td>Bandit</td></tr><tr><td>Bayesian Optimization</td><td>BO</td></tr><tr><td>Hill Climbing</td><td>局部搜索</td></tr><tr><td>LM Proposal</td><td>LM 驅動（用 LLM 建議候選組合）</td></tr><tr><td>Brute-force</td><td>基準（評估所有組合）</td></tr><tr><td>Random search</td><td>基準</td></tr></tbody></table><p><strong>結果</strong>：UCB-E 在相近準確率下，比 brute-force 減少 <strong>62-76%</strong> 的評估預算（v2）。</p><h3 id="四個-benchmark" tabindex="-1">四個 Benchmark <a class="header-anchor" href="#四個-benchmark" aria-label="Permalink to &quot;四個 Benchmark&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>領域</th></tr></thead><tbody><tr><td>HotpotQA</td><td>多跳問答</td></tr><tr><td>GPQA Diamond</td><td>研究所程度科學問答</td></tr><tr><td>MathQA</td><td>數學推理</td></tr><tr><td>BFCL v3</td><td>函式呼叫（工具使用）</td></tr></tbody></table><h3 id="與-llm-routing-的差異" tabindex="-1">與 LLM Routing 的差異 <a class="header-anchor" href="#與-llm-routing-的差異" aria-label="Permalink to &quot;與 LLM Routing 的差異&quot;">​</a></h3><table tabindex="0"><thead><tr><th>LLM Routing</th><th>AgentOpt（Pipeline 優化）</th></tr></thead><tbody><tr><td>每個 query 的決策</td><td>Pipeline 層級優化</td></tr><tr><td>單次 LLM 呼叫</td><td>多階段 pipeline，<strong>各階段賦值相互耦合</strong></td></tr><tr><td>無耦合</td><td>下游依賴上游輸出品質</td></tr></tbody></table><h3 id="對-workspace-的直接映射" tabindex="-1">對 Workspace 的直接映射 <a class="header-anchor" href="#對-workspace-的直接映射" aria-label="Permalink to &quot;對 Workspace 的直接映射&quot;">​</a></h3><p>AgentOpt 的 pipeline 角色對應到 cc-workspace：</p><table tabindex="0"><thead><tr><th>AgentOpt 角色</th><th>Workspace 映射</th></tr></thead><tbody><tr><td>Planner</td><td>Parent Claude Code session（協調者）</td></tr><tr><td>Solver/Executor</td><td>sub-agent（<code>haiku-implementer</code>、<code>implementer</code>）</td></tr><tr><td>Critic/Reviewer</td><td><code>reviewer</code>、<code>security-reviewer</code>、<code>/deep-review</code></td></tr></tbody></table><p><strong>關鍵洞見</strong>：AgentOpt 實驗發現「弱規劃者 + 強求解者」優於「強規劃者獨大」，正是 cc-workspace 的 haiku-pilot 設計哲學的實驗驗證。</p><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>量化驗證 haiku-first 策略</strong>：13-32× 成本差距表示正確的小模型放置節省大量成本，且不損品質</li><li><strong>「Opus 做規劃者反而最差」是反直覺警告</strong>：強模型作為 orchestrator 時，可能反而降低 sub-agent 使用率</li><li><strong>A/B 測試模型組合</strong>：對重複性任務類型，應建立 eval set 測試 Haiku/Sonnet/Opus 組合，用 Arm Elimination / UCB-E 找最佳組合</li><li><strong>效果測量先於假設</strong>：最佳組合往往違反直覺，必須實測而非假設</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>直接驗證 Haiku-first 架構；13-32× 成本差距是給 subagent-strategy.md 的實證基礎</td></tr><tr><td>B. 創新性</td><td>9/10</td><td>「強模型當 planner 反而最差」是反直覺的重要發現；pipeline-level 優化框架本身是新穎貢獻</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>四個 benchmark，10 種算法比較，具體數字（31.71% vs 74.27%，13-32× 成本差距）均可重現</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>Bandit 算法理論、httpx 攔截機制、Pareto frontier 輸出均有具體實作說明</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>四個不同領域的 benchmark 驗證，框架設計為模型無關</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.70/10</strong></td><td>9×0.3 + 9×0.2 + 9×0.2 + 8×0.15 + 8×0.15 = 2.7+1.8+1.8+1.2+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/rules/subagent-strategy.md</code> 和 <code>.claude/refs/model-selection-grid.md</code><br><strong>整合狀態</strong>：待實作（<code>.claude/skills/prompt-token-optimization/</code> 已引用 13-32× 數字）</p><p><strong>TODO</strong>：</p><ul><li>在 subagent-strategy.md 加入 AgentOpt 的實驗結論作為「為什麼 parent 應保持輕量」的量化理由</li><li>在 model-selection-grid.md 加入「強模型當 orchestrator 的反直覺風險」的警告</li><li>考慮設計一個小型 A/B 測試框架，讓常見任務類型的模型選擇可以用數據驗證</li></ul>',35)])])}const b=e(o,[["render",n]]);export{g as __pageData,b as default};
